CREATE TABLE IF NOT EXISTS "notifications" (
  "id" integer NOT NULL DEFAULT nextval('notifications_id_seq'),
  "user_id" integer,
  "type" varchar(100) NOT NULL,
  "title" varchar(255) NOT NULL,
  "message" text NOT NULL,
  "data" text,
  "is_read" boolean NOT NULL DEFAULT false,
  "related_entity" varchar(100),
  "related_id" integer,
  "created_at" timestamp NOT NULL DEFAULT now(),
  "read_at" timestamp,
  PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "permissions" (
  "id" integer NOT NULL DEFAULT nextval('permissions_id_seq'),
  "name" varchar(255) NOT NULL,
  "description" text,
  "category" varchar(255) NOT NULL,
  "created_at" timestamp NOT NULL DEFAULT now(),
  PRIMARY KEY ("id"),
  CONSTRAINT "permissions_name_unique" UNIQUE ("name")
);

CREATE TABLE IF NOT EXISTS "role_permissions" (
  "id" integer NOT NULL DEFAULT nextval('role_permissions_id_seq'),
  "role_id" integer NOT NULL,
  "permission_id" integer NOT NULL,
  "assigned_at" timestamp NOT NULL DEFAULT now(),
  PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "roles" (
  "id" integer NOT NULL DEFAULT nextval('roles_id_seq'),
  "name" varchar(255) NOT NULL,
  "description" text,
  "created_at" timestamp NOT NULL DEFAULT now(),
  "updated_at" timestamp NOT NULL DEFAULT now(),
  PRIMARY KEY ("id"),
  CONSTRAINT "roles_name_unique" UNIQUE ("name")
);

CREATE TABLE IF NOT EXISTS "technician_ratings" (
  "id" integer NOT NULL DEFAULT nextval('technician_ratings_id_seq'),
  "technician_id" integer NOT NULL,
  "work_order_id" integer,
  "rating" integer NOT NULL,
  "comment" text,
  "rated_by" varchar(255) NOT NULL,
  "created_at" timestamp NOT NULL DEFAULT now(),
  PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "technicians" (
  "id" integer NOT NULL DEFAULT nextval('technicians_id_seq'),
  "first_name" varchar(255) NOT NULL,
  "last_name" varchar(255) NOT NULL,
  "email" varchar(255) NOT NULL,
  "phone" varchar(50) NOT NULL,
  "specialization" varchar(255) NOT NULL,
  "experience" integer NOT NULL,
  "hourly_rate" numeric(10,2) NOT NULL,
  "availability" varchar(50) NOT NULL DEFAULT 'available'::character varying,
  "location" varchar(255) NOT NULL,
  "latitude" numeric(10,7),
  "longitude" numeric(10,7),
  "payment_methods" text NOT NULL,
  "bank_account" varchar(255),
  "routing_number" varchar(255),
  "bank_name" varchar(255),
  "paypal_email" varchar(255),
  "venmo_handle" varchar(255),
  "cashapp_handle" varchar(255),
  "zelle_info" text,
  "mailing_address" text,
  "average_rating" numeric(3,2) DEFAULT '0'::numeric,
  "total_ratings" integer DEFAULT 0,
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamp NOT NULL DEFAULT now(),
  "updated_at" timestamp NOT NULL DEFAULT now(),
  "w9_status" varchar(50) DEFAULT 'not_submitted'::character varying,
  "w9_file_path" varchar(500),
  "w9_file_name" varchar(255),
  "w9_submitted_at" timestamp,
  PRIMARY KEY ("id"),
  CONSTRAINT "technicians_email_unique" UNIQUE ("email")
);

CREATE TABLE IF NOT EXISTS "user_roles" (
